namespace App\Domain\Combat\Data;use App\Domain\Combat\CombatActionType;use InvalidArgumentException;final class CombatCommand {private $commandId;private $actor;private $type;private $target;public function __construct($commandId,$actor,$type,$target){if(($commandId!==null&&trim((string)$commandId)==='')||trim((string)$actor)===''||trim((string)$target)===''||!in_array($type,CombatActionType::values(),true))throw new InvalidArgumentException('Invalid combat command.');$this->commandId=$commandId;$this->actor=$actor;$this->type=$type;$this->target=$target;}public function commandId(){return$this->commandId;}public function actorIdentifier(){return$this->actor;}public function actionType(){return$this->type;}public function targetIdentifier(){return$this->target;}}
